  function esc(v){ return String(v==null?'':v).replace(/[&<>"']/g, ch=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[ch])); }
  function nl(v){ return esc(v).replace(/\n/g,'<br>'); }
  function uid(){ return session&&session.user&&session.user.id; }
  function isAdmin(){ return (session?.user?.email||'').toLowerCase()===ADMIN_EMAIL; }
  function lessonList(){ return DATA.lessons[lang()]||DATA.lessons.fa||[]; }
  function examList(){ return DATA.exam[lang()]||DATA.exam.fa||[]; }
  function lessonByCode(code){ return lessonList().find(x=>x.code===code) || (DATA.lessons.fa||[]).find(x=>x.code===code); }
  function completedSet(){ return new Set((progress||[]).filter(p=>p.completed).map(p=>p.lesson_code)); }
  function isUnlocked(lesson){ const list=lessonList(); if(lesson.order===1) return true; const prev=list.find(x=>x.order===lesson.order-1); return prev && completedSet().has(prev.code); }
  function allCompleted(){ const set=completedSet(); return lessonList().every(l=>set.has(l.code)); }
  function noteFor(code, idx){ return (notes||[]).find(n=>n.lesson_code===code && Number(n.note_index)===idx)?.note_text || ''; }
  function assignmentFor(code){ return (assignments||[]).find(a=>a.lesson_code===code) || null; }
  function assignmentText(code){ return assignmentFor(code)?.assignment_text || ''; }
  function showStatus(msg, bad){ const el=document.querySelector('#schoolStatus'); if(el){ el.textContent=msg||''; el.style.color=bad?'#b00020':'#0a6b2b'; } }
  function schoolTerms(){ return DATA.terms[lang()]||DATA.terms.fa||DATA.terms.en||{}; }

  function loadScript(src){
    return new Promise((res,rej)=>{
      if(window.supabase?.createClient){ res(); return; }
      let existing=document.querySelector('script[data-om7-supabase-sdk][src="'+src+'"]');
      let done=false;
      let timer=setTimeout(()=>{ if(done) return; done=true; rej(new Error('Supabase SDK load timeout')); },9000);
      function ok(){ if(done) return; done=true; clearTimeout(timer); res(); }
      function bad(){ if(done) return; done=true; clearTimeout(timer); rej(new Error('Supabase SDK load failed')); }
      if(existing){ existing.addEventListener('load',ok,{once:true}); existing.addEventListener('error',bad,{once:true}); setTimeout(()=>{ if(window.supabase?.createClient) ok(); },300); return; }
      const s=document.createElement('script'); s.src=src; s.async=true; s.dataset.om7SupabaseSdk='1'; s.onload=ok; s.onerror=bad; document.head.appendChild(s);
    });
  }
  async function ensureSupabase(){
    if(sb) return sb;
    if(window.OMIDENO7_GET_SUPABASE_CLIENT){
      sb=await window.OMIDENO7_GET_SUPABASE_CLIENT();
    }
    if(!sb && window.OMIDENO7_SUPABASE_READY){
      sb=await window.OMIDENO7_SUPABASE_READY;
    }
    if(!sb){
      if(!window.supabase?.createClient){
        const urls=['https://cdn.jsdelivr.net/npm/@supabase/supabase-js@2','https://unpkg.com/@supabase/supabase-js@2/dist/umd/supabase.js','https://cdn.jsdelivr.net/npm/@supabase/supabase-js@2/dist/umd/supabase.min.js'];
        let lastErr=null;
        for(const u of urls){ try{ await loadScript(u); if(window.supabase?.createClient) break; }catch(e){ lastErr=e; } }
        if(!window.supabase?.createClient) throw (lastErr||new Error('Supabase SDK could not be loaded. Please check internet connection and reload the app.'));
      }
      sb=window.supabase.createClient(SUPABASE_URL, SUPABASE_KEY,{auth:{persistSession:true,autoRefreshToken:true,detectSessionInUrl:true}});
      window.omideno7Supabase=sb; window.schoolSupabase=sb; window.supabaseClient=sb;
    }
    const {data}=await sb.auth.getSession(); session=data?.session||null;
    if(!sb.__om7SchoolAuthBound){ sb.__om7SchoolAuthBound=true; sb.auth.onAuthStateChange((_event, sess)=>{ session=sess; refreshSchool(); }); }
    return sb;
  }

  function injectStyle(){
    if(document.getElementById('v63-school-style')) return;
    const css=`
      #school .school-shell{max-width:980px;margin:0 auto;padding:8px 12px 90px}.school-hero{background:linear-gradient(135deg,#06146D,#0d2aa8);color:#fff!important;border-radius:24px;padding:22px;margin:10px 0 14px;box-shadow:0 12px 32px rgba(6,20,109,.22)}.school-hero h1{margin:0 0 8px;font-size:1.65rem;color:#fff!important;font-weight:900!important;text-shadow:0 2px 6px rgba(0,0,0,.18)}.school-hero p{margin:0;color:#e9eeff!important;opacity:1!important;font-weight:600}.school-tabs{display:flex;gap:8px;overflow:auto;margin:12px 0}.school-tab{border:0;border-radius:999px;padding:10px 14px;background:#eef1ff;color:#06146D;font-weight:700;white-space:nowrap}.school-tab.active{background:#d5a600;color:#161000}.school-card{background:#fff;border:1px solid rgba(6,20,109,.12);border-radius:22px;padding:16px;margin:12px 0;box-shadow:0 8px 28px rgba(6,20,109,.08)}.school-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:12px}.school-form{display:grid;gap:10px}.school-form label{font-weight:700;color:#06146D}.school-form input,.school-form select,.school-form textarea{width:100%;box-sizing:border-box;border:1px solid #ccd3ee;border-radius:14px;padding:11px;background:#fff;font:inherit}.school-form textarea{min-height:92px;resize:vertical}.school-btn{border:0;border-radius:14px;padding:11px 14px;font-weight:800;background:#06146D;color:white}.school-btn.gold{background:#d5a600;color:#140e00}.school-btn.light{background:#eef1ff;color:#06146D}.school-btn:disabled{opacity:.45}.lesson-card.locked{opacity:.58}.school-badge{display:inline-block;border-radius:999px;padding:5px 9px;background:#eef1ff;color:#06146D;font-size:.8rem;font-weight:800}.school-badge.done{background:#e6f8ee;color:#086b31}.school-badge.active{background:#fff3c4;color:#6f5400}.school-progressbar{height:12px;background:#eef1ff;border-radius:999px;overflow:hidden}.school-progressbar span{display:block;height:100%;background:#d5a600}.school-lesson-text{line-height:1.85;font-size:1rem}.school-note-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(240px,1fr));gap:10px}.school-note{min-height:90px}.school-audio{width:100%;margin:8px 0}.school-result-good{background:#e6f8ee;border-color:#99dbb5}.school-result-bad{background:#fff0f0;border-color:#f0b0b0}.school-question{border:1px solid #e3e7f8;border-radius:18px;padding:12px;margin:10px 0}.school-option{display:block;margin:8px 0;padding:8px 10px;border-radius:12px;background:#f7f8ff}.school-admin-table{width:100%;border-collapse:collapse}.school-admin-table th,.school-admin-table td{border-bottom:1px solid #e5e8f5;padding:8px;text-align:start;vertical-align:top}.bottom-nav .nav-inner{display:grid!important;grid-template-columns:repeat(6,minmax(0,1fr))!important;gap:0!important;align-items:center!important}.bottom-nav .nav-btn{min-width:0!important;width:100%!important;padding:5px 1px!important;display:flex!important;flex-direction:column!important;align-items:center!important;justify-content:center!important;gap:2px!important;white-space:nowrap!important}.bottom-nav .nav-btn .icon{font-size:1rem!important;line-height:1!important}.bottom-nav .nav-btn span:last-child,.bottom-nav .school-nav-label{font-size:.64rem!important;line-height:1.1!important;font-weight:800!important}.bottom-nav{overflow:hidden!important}.school-nav-btn{margin:0!important;position:static!important}.fa #school{text-align:right;direction:rtl}.en #school,.hr #school{direction:ltr}.school-muted{color:#65708f;font-size:.92rem}#schoolStatus{min-height:22px;font-weight:700}.school-danger{color:#b00020}`;
    const st=document.createElement('style'); st.id='v63-school-style'; st.textContent=css; document.head.appendChild(st);
  }

  function ensureUi(){
    injectStyle();
    let main=document.querySelector('main')||document.body;
    if(!document.getElementById('school')){
      const sec=document.createElement('section'); sec.id='school'; sec.className='page'; main.appendChild(sec);
    }
    const navInner=document.querySelector('.bottom-nav .nav-inner');
    if(navInner){
      let btn=navInner.querySelector('[data-page="school"]');
      if(!btn){
        btn=document.createElement('button');
        btn.className='nav-btn school-nav-btn';
        btn.setAttribute('data-page','school');
        btn.innerHTML=`<span class="icon">🎓</span><span class="school-nav-label">${esc(tr('nav'))}</span>`;
      }
      const moreBtn=navInner.querySelector('[data-page="more"]');
      if(moreBtn && btn.nextElementSibling!==moreBtn){
        navInner.insertBefore(btn, moreBtn);
      } else if(!moreBtn && !btn.parentNode){
        navInner.appendChild(btn);
      }
    }
    document.querySelectorAll('.school-nav-label').forEach(e=>e.textContent=tr('nav'));
    document.querySelectorAll('[data-page="school"]').forEach(btn=>{ btn.onclick=(ev)=>{ ev.preventDefault(); showSchool(); }; });
    document.querySelectorAll('.lang-toggle button').forEach(b=>b.addEventListener('click',()=>setTimeout(()=>{document.querySelectorAll('.school-nav-label').forEach(e=>e.textContent=tr('nav')); if(document.getElementById('school')?.classList.contains('active')) render();},120)));
  }
  function showSchool(){
    document.querySelectorAll('main .page, .page').forEach(p=>p.classList.remove('active'));
    document.getElementById('school')?.classList.add('active');
    document.querySelectorAll('.bottom-nav .nav-btn').forEach(b=>b.classList.toggle('active', b.getAttribute('data-page')==='school'));
    window.scrollTo({top:0,behavior:'smooth'}); refreshSchool();
  }

  async function refreshSchool(){
    ensureUi();
    const root=document.getElementById('school'); if(!root) return;
    root.innerHTML=`<div class="school-shell"><div class="school-hero"><h1>${esc(tr('title'))}</h1><p>${esc(tr('subtitle'))}</p></div><div class="school-card">${esc(tr('loading'))}</div></div>`;
    try{ await ensureSupabase(); await loadAll(); render(); }catch(e){ console.error(e); root.innerHTML=`<div class="school-shell"><div class="school-hero"><h1>${esc(tr('title'))}</h1><p>${esc(tr('subtitle'))}</p></div><div class="school-card school-danger">${esc(e.message||String(e))}</div></div>`; }
  }
  async function loadAll(){
    if(!sb) return;
    const {data}=await sb.auth.getSession(); session=data?.session||session;
    student=null; progress=[]; notes=[]; assignments=[]; attempts=[];
    if(!session?.user) return;
    let r=await sb.from('school_students').select('*').eq('user_id', uid()).maybeSingle();
    if(r.error && r.error.code!=='PGRST116') throw r.error;
    student=r.data||null;
    if(student){
      let [pr,no,as,at]=await Promise.all([
        sb.from('school_progress').select('*').eq('user_id',uid()),
        sb.from('school_notes').select('*').eq('user_id',uid()),
        sb.from('school_assignments').select('*').eq('user_id',uid()),
        sb.from('school_exam_attempts').select('*').eq('user_id',uid()).order('attempt_number',{ascending:true})
      ]);
      if(pr.error) throw pr.error; if(no.error) throw no.error; if(as.error) throw as.error; if(at.error) throw at.error;
      progress=pr.data||[]; notes=no.data||[]; assignments=as.data||[]; attempts=at.data||[];
    }
  }
  function render(){
    const root=document.getElementById('school'); if(!root) return;
    const adminTab=isAdmin()?`<button class="school-tab ${activeView==='admin'?'active':''}" data-school-view="admin">${esc(tr('admin'))}</button>`:'';
    root.innerHTML=`<div class="school-shell"><div class="school-hero"><h1>${esc(tr('title'))}</h1><p>${esc(tr('subtitle'))}</p></div><div id="schoolStatus"></div>${session?.user?`<div class="school-card"><strong>${esc(session.user.email||'')}</strong> <button class="school-btn light" id="schoolLogout">${esc(tr('logout'))}</button></div>`:''}${session?.user&&(student||isAdmin())?`<div class="school-tabs"><button class="school-tab ${activeView==='dashboard'?'active':''}" data-school-view="dashboard">${esc(tr('dashboard'))}</button><button class="school-tab ${activeView==='lessons'?'active':''}" data-school-view="lessons">${esc(tr('lessons'))}</button><button class="school-tab ${activeView==='exam'?'active':''}" data-school-view="exam">${esc(tr('exam'))}</button>${adminTab}</div>`:''}<div id="schoolBody"></div></div>`;
    document.getElementById('schoolLogout')?.addEventListener('click', async()=>{ await sb.auth.signOut(); session=null; student=null; render(); });
    document.querySelectorAll('[data-school-view]').forEach(b=>b.addEventListener('click',()=>{activeView=b.dataset.schoolView; activeLesson=null; render();}));
    const body=document.getElementById('schoolBody');
    if(!session?.user){ body.innerHTML=authHtml(); bindAuth(); return; }
    if(isAdmin() && !student && activeView!=='admin') activeView='admin';
    if(!student && !isAdmin()){ body.innerHTML=registrationHtml(); bindRegistration(); return; }
    if(student && !studentApproved() && !isAdmin()){ body.innerHTML=pendingApprovalHtml(); return; }
    if(activeLesson){ body.innerHTML=lessonHtml(activeLesson); bindLesson(activeLesson); return; }
    if(activeView==='admin' && isAdmin()) { body.innerHTML=adminHtml(); bindAdmin(); return; }
    if(activeView==='lessons') { body.innerHTML=lessonsHtml(); bindLessons(); return; }
    if(activeView==='exam') { body.innerHTML=examHtml(); bindExam(); return; }
    body.innerHTML=dashboardHtml(); bindDashboard();
  }
  function authHtml(){ return `<div class="school-grid"><div class="school-card"><h2>${esc(tr('login'))}</h2><p class="school-muted">${esc(tr('noAccess'))}</p><form id="schoolLogin" class="school-form"><label>${esc(tr('email'))}<input name="email" type="email" required></label><label>${esc(tr('password'))}<input name="password" type="password" required minlength="6"></label><button class="school-btn" type="submit">${esc(tr('signIn'))}</button></form></div><div class="school-card"><h2>${esc(tr('signup'))}</h2><form id="schoolSignup" class="school-form"><label>${esc(tr('email'))}<input name="email" type="email" required></label><label>${esc(tr('password'))}<input name="password" type="password" required minlength="6"></label><button class="school-btn gold" type="submit">${esc(tr('createAccount'))}</button></form></div></div>`; }
  function bindAuth(){
    document.getElementById('schoolLogin')?.addEventListener('submit', async e=>{ e.preventDefault(); const f=new FormData(e.target); showStatus(tr('loading')); const {error}=await sb.auth.signInWithPassword({email:f.get('email'), password:f.get('password')}); if(error) showStatus(error.message,true); else {await loadAll(); render();} });
    document.getElementById('schoolSignup')?.addEventListener('submit', async e=>{
      e.preventDefault();
      const form=e.target;
      const f=new FormData(form);
      const email=String(f.get('email')||'').trim();
      const password=String(f.get('password')||'');
      if(!email||!password){ showStatus(tr('required'),true); return; }
      showStatus(tr('loading'));
      const {data,error}=await sb.auth.signUp({email, password});
      if(error){ showStatus(error.message,true); return; }
      session=data?.session||session;
      if(session?.user){
        showStatus(tr('accountCreated'));
        await loadAll();
        activeView='dashboard';
        render();
        return;
      }
      // If Supabase email confirmation is enabled, signUp returns no session.
      // Keep the form visible and show a clear message instead of re-rendering and clearing the fields.
      const l=lang();
      const msg={
        fa:'حساب شما ساخته شد. لطفاً صندوق ورودی ایمیل خود را باز کنید، ایمیل تأیید را بزنید، سپس با همین ایمیل و رمز وارد مدرسه شوید. بعد از ورود، فرم ثبت‌نام مدرسه را کامل کنید و منتظر تأیید ادمین بمانید.',
        en:'Your account has been created. Please open your email inbox, confirm your email address, then sign in with the same email and password. After signing in, complete the school registration form and wait for admin approval.',
        hr:'Vaš račun je izrađen. Otvorite svoj email, potvrdite email adresu, zatim se prijavite istim emailom i lozinkom. Nakon prijave ispunite obrazac za školu i pričekajte odobrenje administratora.'
      }[l]||'Your account has been created. Please confirm your email, sign in, complete the school form, and wait for admin approval.';
      showStatus(msg);
    });
  }
  function registrationHtml(){ const terms=schoolTerms(); return `<div class="school-card"><h2>${esc(tr('signup'))}</h2><p>${nl(terms.terms||'')}</p><form id="schoolRegistration" class="school-form"><div class="school-grid"><label>${esc(tr('fullName'))}*<input name="full_name" required></label><label>${esc(tr('phone'))}*<input name="phone" required></label><label>${esc(tr('country'))}*<input name="country" required></label><label>${esc(tr('city'))}*<input name="city" required></label><label>${esc(tr('language'))}*<select name="preferred_language" required><option value="fa">فارسی</option><option value="en">English</option><option value="hr">Hrvatski</option></select></label><label>${esc(tr('isBeliever'))}*<select name="is_believer"><option value="true">${esc(tr('yes'))}</option><option value="false">${esc(tr('no'))}</option></select></label><label>${esc(tr('yearsBeliever'))}*<input name="years_believer" required></label><label>${esc(tr('otherChurch'))}*<select name="is_member_of_another_church"><option value="false">${esc(tr('no'))}</option><option value="true">${esc(tr('yes'))}</option></select></label><label>${esc(tr('churchName'))}*<input name="church_name" required placeholder="${lang()==='fa'?'ندارم':'None'}"></label><label>${esc(tr('pastorName'))}*<input name="pastor_name" required placeholder="${lang()==='fa'?'ندارم':'None'}"></label><label>${esc(tr('pastorPhone'))}*<input name="pastor_phone" required placeholder="${lang()==='fa'?'ندارم':'None'}"></label></div><label>${esc(tr('testimony'))}*<textarea name="testimony" required></textarea></label><label><input type="checkbox" name="accepted" required> ${esc(terms.acceptance||tr('accept'))}</label><button class="school-btn gold" type="submit">${esc(tr('createAccount'))}</button></form></div>`; }
  
function bindRegistration(){
    document.getElementById('schoolRegistration')?.addEventListener('submit', async e=>{
      e.preventDefault();
      e.stopPropagation();
      if(e.stopImmediatePropagation) e.stopImmediatePropagation();
      const form=e.target;
      const f=new FormData(form);
      if(!f.get('accepted')){showStatus(tr('required'),true);return;}
      if(!session?.user?.id){showStatus('User session not found. Please sign in again.',true);return;}
      const row={
        user_id:uid(),
        full_name:String(f.get('full_name')||'').trim(),
        email:session.user.email,
        phone:String(f.get('phone')||'').trim(),
        country:String(f.get('country')||'').trim(),
        city:String(f.get('city')||'').trim(),
        preferred_language:f.get('preferred_language')||lang(),
        is_believer:f.get('is_believer')==='true',
        years_believer:String(f.get('years_believer')||'').trim(),
        testimony:String(f.get('testimony')||'').trim(),
        is_member_of_another_church:f.get('is_member_of_another_church')==='true',
        church_name:String(f.get('church_name')||'').trim() || 'None',
        pastor_name:String(f.get('pastor_name')||'').trim() || 'None',
        pastor_phone:String(f.get('pastor_phone')||'').trim() || 'None',
        accepted_membership_requirement:true,
        status:'pending_review',
        updated_at:new Date().toISOString()
      };
      const requiredKeys=['full_name','email','phone','country','city','preferred_language','years_believer','testimony','church_name','pastor_name','pastor_phone'];
      for(const k of requiredKeys){ if(!String(row[k]||'').trim()){showStatus(tr('required')+' — '+k,true); return;} }
      showStatus(tr('loading'));
      let result=await sb.from('school_students').insert(row).select('user_id,email,status').single();
      if(result.error && /duplicate|already exists|unique/i.test(String(result.error.message||''))){
        result=await sb.from('school_students').update(row).eq('user_id',uid()).select('user_id,email,status').single();
      }
      if(result.error){
        showStatus(result.error.message,true);
        alert(result.error.message);
        return;
      }
      await loadAll();
      activeView='dashboard';
      render();
    }, true);
  }
  function pendingApprovalHtml(){ return `<div class="school-card"><h2>${esc(schoolTxt('pendingTitle'))}</h2><p>${esc(schoolTxt('pending'))}</p><p><strong>${esc(tr('fullName'))}:</strong> ${esc(student?.full_name||'')}</p><p><strong>${esc(tr('email'))}:</strong> ${esc(student?.email||session?.user?.email||'')}</p><p><span class="school-badge active">${esc(schoolTxt('pendingReview'))}</span></p></div>`; }
