  function lessonsHtml(){ return `<div class="school-grid">${lessonList().map(l=>{ const done=completedSet().has(l.code), unlocked=isUnlocked(l); return `<div class="school-card lesson-card ${unlocked?'':'locked'}"><span class="school-badge ${done?'done':unlocked?'active':''}">${done?tr('completed'):unlocked?tr('current'):tr('locked')}</span><h3>${esc(l.classTitle)}</h3><p><strong>${esc(l.title)}</strong></p><button class="school-btn ${done?'light':''}" data-open-lesson="${esc(l.code)}" ${unlocked?'':'disabled'}>${esc(tr('open'))}</button></div>`; }).join('')}</div>`; }
  function bindLessons(){ document.querySelectorAll('[data-open-lesson]').forEach(b=>b.addEventListener('click',()=>{activeLesson=b.dataset.openLesson; render(); window.scrollTo({top:0,behavior:'smooth'});})); }

  function resolveSchoolAudio(path){
    const base='https://uibhpgcsgcievktxmcfg.supabase.co/storage/v1/object/public/school-audio/';
    let file=String(path||'').split('/').pop();
    const shared={
      'class-06-fa.mp3':'class-06-07-fa.mp3',
      'class-07-fa.mp3':'class-06-07-fa.mp3',
      'class-06-fa.m4a':'class-06-07-fa.mp3',
      'class-07-fa.m4a':'class-06-07-fa.mp3'
    };
    file=shared[file]||file.replace(/\.m4a$/i,'.mp3');
    return base + encodeURIComponent(file);
  }

  function lessonHtml(code){
    const l=lessonByCode(code);
    if(!l) return `<div class="school-card">Lesson not found</div>`;
    const done=completedSet().has(code);
    const a=assignmentText(code);
    const fullLabel=l.textButtonLabel||({fa:'متن کامل درس',en:'Full Written Lesson',hr:'Cijela pisana lekcija'}[lang()]||'Full lesson');
    const scriptureLabel={fa:'آیات کلیدی',en:'Key Scriptures',hr:'Ključni stihovi'}[lang()]||'Key Scriptures';
    const audio=(lang()==='fa'&&l.audioFile)?`<div class="school-card"><h3>${esc(tr('audio'))}</h3><audio id="schoolAudio" class="school-audio" controls preload="metadata" src="${esc(resolveSchoolAudio(l.audioFile))}"></audio><label>${esc(tr('speed'))}<select id="schoolSpeed"><option>0.75</option><option selected>1</option><option>1.25</option><option>1.5</option><option>2</option></select></label></div>`:`<div class="school-card"><h3>${esc(tr('audio'))}</h3><p>${esc(lang()==='en'?UI.en.audioLater:lang()==='hr'?UI.hr.audioLater:'فایل صوتی این زبان هنوز آماده نیست. لطفاً متن درس را با دقت مطالعه کنید.')}</p></div>`;
    return `<button class="school-btn light" id="backToLessons">${esc(tr('back'))}</button>
    <div class="school-card"><span class="school-badge ${done?'done':'active'}">${done?tr('completed'):tr('current')}</span><h2>${esc(l.classTitle)}</h2><h3>${esc(l.title)}</h3>${l.keyScriptures?`<p><strong>${esc(scriptureLabel)}:</strong></p>${keyScriptureButtons(l)}`:''}<details class="school-card"><summary class="school-btn gold" style="display:inline-block;cursor:pointer">${esc(fullLabel)}</summary><div class="school-lesson-text" style="margin-top:14px;max-height:62vh;overflow:auto;padding:4px 2px">${nl(l.text)}</div></details></div>
    ${audio}
    <div class="school-card"><h3>${esc(tr('notes'))}</h3><p class="school-muted">${esc(tr('minNotes'))}</p><div class="school-note-grid">${Array.from({length:l.minNotes},(_,i)=>`<label>${esc(tr('note'))} ${i+1}<textarea class="school-note" data-note-index="${i+1}">${esc(noteFor(code,i+1))}</textarea></label>`).join('')}</div><button class="school-btn" id="saveNotes">${esc(tr('saved'))}</button></div>
    <div class="school-card"><h3>${esc(tr('assignment'))}</h3><p>${nl(l.assignment)}</p><textarea id="assignmentText" style="width:100%;min-height:140px">${esc(a)}</textarea><br><button class="school-btn" id="saveAssignment">${esc(tr('submitAssignment'))}</button><button class="school-btn gold" id="completeLesson">${esc(tr('completeLesson'))}</button></div>`;
  }
  function bindLesson(code){
    document.getElementById('backToLessons')?.addEventListener('click',()=>{activeLesson=null; activeView='lessons'; render();});
    document.getElementById('schoolSpeed')?.addEventListener('change',e=>{ const au=document.getElementById('schoolAudio'); if(au) au.playbackRate=parseFloat(e.target.value||'1'); });
    bindKeyScriptureButtons(document.getElementById('schoolBody')||document);
    document.getElementById('saveNotes')?.addEventListener('click',()=>saveNotes(code));
    document.getElementById('saveAssignment')?.addEventListener('click',()=>saveAssignment(code));
    document.getElementById('completeLesson')?.addEventListener('click',()=>completeLesson(code));
  }
  async function saveNotes(code){ const rows=[...document.querySelectorAll('[data-note-index]')].map(el=>({user_id:uid(), lesson_code:code, note_index:Number(el.dataset.noteIndex), note_text:el.value.trim()})); showStatus(tr('loading')); const {error}=await sb.from('school_notes').upsert(rows,{onConflict:'user_id,lesson_code,note_index'}); if(error) showStatus(error.message,true); else {await loadAll(); showStatus(tr('saved'));} }
  async function saveAssignment(code){ const text=document.getElementById('assignmentText')?.value.trim()||''; if(!text){showStatus(tr('required'),true);return false;} const {error}=await sb.from('school_assignments').upsert({user_id:uid(),lesson_code:code,assignment_text:text,status:'submitted'},{onConflict:'user_id,lesson_code'}); if(error){showStatus(error.message,true);return false;} await loadAll(); showStatus(tr('saved')); return true; }
  async function completeLesson(code){ await saveNotes(code); const okA=await saveAssignment(code); if(!okA) return; const l=lessonByCode(code); const filled=[...document.querySelectorAll('[data-note-index]')].filter(x=>x.value.trim().length>=3).length; const asg=document.getElementById('assignmentText')?.value.trim()||''; if(filled<(l.minNotes||15)||!asg){ showStatus(tr('minNotes'),true); return; } const {error}=await sb.from('school_progress').upsert({user_id:uid(),lesson_code:code,completed:true,completed_at:new Date().toISOString()},{onConflict:'user_id,lesson_code'}); if(error) showStatus(error.message,true); else {await loadAll(); activeLesson=null; activeView='lessons'; render(); showStatus(tr('nextUnlocked'));} }
  function canTakeExam(){ const last=attempts[attempts.length-1]; if(!allCompleted()) return false; if(!last) return true; if(last.passed) return false; return attempts.length<DATA.maxAttempts; }
  function examHtml(){ if(!allCompleted()) return `<div class="school-card"><h2>${esc(tr('exam'))}</h2><p>${esc(tr('finalExamLocked'))}</p></div>`; const last=attempts[attempts.length-1]; if(last && (last.passed || attempts.length>=DATA.maxAttempts)) return examResultHtml(last); return `<div class="school-card"><h2>${esc(tr('exam'))}</h2><p>${esc(tr('score'))}: ${DATA.passMark}%</p>${last?`<div class="school-card school-result-bad"><strong>${tr('fail')}</strong><p>${tr('retry')}</p></div>`:''}<button class="school-btn gold" id="startSchoolExam">${esc(tr('startExam'))}</button></div><div id="schoolExamArea"></div>`; }
  function bindExam(){ document.getElementById('startSchoolExam')?.addEventListener('click',()=>{ const area=document.getElementById('schoolExamArea'); area.innerHTML=`<form id="schoolExamForm">${examList().map(q=>`<div class="school-question"><h4>${q.number}. ${esc(q.question)}</h4>${q.options.map(o=>`<label class="school-option"><input type="radio" name="q${q.number}" value="${o.key}" required> ${o.key}. ${esc(o.text)}</label>`).join('')}</div>`).join('')}<button class="school-btn gold" type="submit">${esc(tr('submitExam'))}</button></form>`; area.scrollIntoView({behavior:'smooth'}); document.getElementById('schoolExamForm').addEventListener('submit',submitExam); }); }
  async function submitExam(e){ e.preventDefault(); const f=new FormData(e.target); const qs=examList(); let correct=0; const answers=qs.map(q=>{ const sel=f.get('q'+q.number)||''; const ok=sel===q.correct; if(ok) correct++; return {question_number:q.number, selected_answer:sel, correct_answer:q.correct, is_correct:ok, question_text:q.question}; }); const pct=Math.round(correct/qs.length*100); const attemptNumber=(attempts.length||0)+1; const {data,error}=await sb.from('school_exam_attempts').insert({user_id:uid(),attempt_number:attemptNumber,total_questions:qs.length,correct_count:correct,wrong_count:qs.length-correct,score_percent:pct,passed:pct>=DATA.passMark}).select('id').single(); if(error){showStatus(error.message,true);return;} const rows=answers.map(a=>({...a,attempt_id:data.id,user_id:uid()})); const e2=await sb.from('school_exam_answers').insert(rows); if(e2.error){showStatus(e2.error.message,true);return;} await loadAll(); render(); }
  function examResultHtml(att){ return `<div class="school-card ${att.passed?'school-result-good':'school-result-bad'}"><h2>${esc(tr('exam'))}</h2><p><strong>${esc(tr('score'))}:</strong> ${att.correct_count}/${att.total_questions}</p><p><strong>${esc(tr('percent'))}:</strong> ${att.score_percent}%</p><p><strong>${att.passed?esc(tr('pass')):esc(tr('fail'))}</strong></p><button class="school-btn" id="loadExamReview">${esc(tr('review'))}</button></div><div id="examReview"></div>`; }
  async function bindExamReview(att){ }
  document.addEventListener('click', async e=>{ if(e.target&&e.target.id==='loadExamReview'){ const att=attempts[attempts.length-1]; const {data,error}=await sb.from('school_exam_answers').select('*').eq('attempt_id',att.id).order('question_number'); if(error){showStatus(error.message,true);return;} const qs=examList(); document.getElementById('examReview').innerHTML=(data||[]).map(a=>{ const q=qs.find(x=>x.number===a.question_number); const selected=q?.options.find(o=>o.key===a.selected_answer)?.text||''; const right=q?.options.find(o=>o.key===a.correct_answer)?.text||''; return `<div class="school-question ${a.is_correct?'school-result-good':'school-result-bad'}"><h4>${a.question_number}. ${esc(a.question_text)}</h4><p>${esc(tr('selected'))}: ${esc(a.selected_answer)} ${esc(selected)}</p><p>${esc(tr('rightAnswer'))}: ${esc(a.correct_answer)} ${esc(right)}</p></div>`; }).join(''); }});
